import{_ as d,o as a,c as e,a6 as r}from"./chunks/framework.wLlb4ebq.js";const m=JSON.parse('{"title":"GitHub Adapter","description":"","frontmatter":{},"headers":[],"relativePath":"integrations/github.md","filePath":"integrations/github.md"}'),i={name:"integrations/github.md"};function n(l,t,o,s,h,b){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="github-adapter" tabindex="-1">GitHub Adapter <a class="header-anchor" href="#github-adapter" aria-label="Permalink to “GitHub Adapter”">​</a></h1><p>GitHub adapter 负责读取 Stars、Repos、Forks 和 Gists，并将仓库元信息、README 语义和用户选择映射到 Notion 数据库条目。</p><h2 id="extraction-rules" tabindex="-1">Extraction rules <a class="header-anchor" href="#extraction-rules" aria-label="Permalink to “Extraction rules”">​</a></h2><table tabindex="0"><thead><tr><th>Rule</th><th>Description</th></tr></thead><tbody><tr><td>Stars</td><td>读取用户 star 的仓库列表</td></tr><tr><td>Repos</td><td>读取用户拥有的仓库</td></tr><tr><td>Forks</td><td>读取 fork 过的仓库</td></tr><tr><td>Gists</td><td>读取代码片段</td></tr><tr><td>README enrichment</td><td>对仓库 README 做摘要和分类增强</td></tr><tr><td>Token optional</td><td>未配置 token 时仍可请求，但速率限制更低</td></tr></tbody></table><h2 id="metadata-fields" tabindex="-1">Metadata fields <a class="header-anchor" href="#metadata-fields" aria-label="Permalink to “Metadata fields”">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Meaning</th></tr></thead><tbody><tr><td>fullName</td><td><code>owner/repo</code></td></tr><tr><td>url</td><td>仓库或 gist URL</td></tr><tr><td>description</td><td>GitHub 描述</td></tr><tr><td>language</td><td>主语言</td></tr><tr><td>stars</td><td>Star 数</td></tr><tr><td>topics</td><td>GitHub topics</td></tr><tr><td>readmeExcerpt</td><td>README 摘要</td></tr></tbody></table><h2 id="normalized-schema-mapping" tabindex="-1">normalized schema mapping <a class="header-anchor" href="#normalized-schema-mapping" aria-label="Permalink to “normalized schema mapping”">​</a></h2><table tabindex="0"><thead><tr><th>Source field</th><th>normalizedContent field</th><th>Destination</th></tr></thead><tbody><tr><td>full name / gist id</td><td>identity.sourceId</td><td>来源 ID</td></tr><tr><td>html_url</td><td>identity.url</td><td>链接</td></tr><tr><td>name + description</td><td>content.title / excerpt</td><td>标题 / 摘要</td></tr><tr><td>README</td><td>content.body</td><td>页面正文或说明</td></tr><tr><td>language / topics</td><td>metadata.tags</td><td>标签</td></tr><tr><td>stars / forks</td><td>metadata.extra</td><td>数字属性</td></tr></tbody></table><h2 id="fallback-behavior" tabindex="-1">fallback behavior <a class="header-anchor" href="#fallback-behavior" aria-label="Permalink to “fallback behavior”">​</a></h2><table tabindex="0"><thead><tr><th>Failure</th><th>fallback behavior</th></tr></thead><tbody><tr><td>GitHub token missing</td><td>使用未认证 API，提示速率限制更低</td></tr><tr><td>README 读取失败</td><td>只使用仓库描述和 topics</td></tr><tr><td>某类导入未勾选</td><td>跳过该类型</td></tr><tr><td>API rate limited</td><td>显示限制提示并建议配置 token</td></tr><tr><td>AI 分类失败</td><td>使用语言、topics 和规则分类</td></tr></tbody></table><h2 id="known-limitations" tabindex="-1">Known limitations <a class="header-anchor" href="#known-limitations" aria-label="Permalink to “Known limitations”">​</a></h2><ul><li>未认证请求受 GitHub rate limit 影响。</li><li>README 内容过大时只能使用摘要或前段内容。</li><li>私有仓库需要 token 具备访问权限。</li><li>GitHub 元数据不等同于项目质量判断，AI 分类只是辅助。</li></ul>',12)])])}const p=d(i,[["render",n]]);export{m as __pageData,p as default};
